state:
num : Int
den g : Nat
den_nz : den / g ≠ 0
reduced : (num.div ↑g).natAbs.Coprime (den / g)
hn : ↑g ∣ num
hd : g ∣ den
⊢ (if hg : g = 1 then { num := num, den := den, den_nz := ⋯, reduced := ⋯ }
    else { num := num.div ↑g, den := den / g, den_nz := den_nz, reduced := reduced }) =
    { num := num / ↑(num.natAbs.gcd den), den := den / num.natAbs.gcd den, den_nz := ⋯, reduced := ⋯ }
